import React, { useState, useEffect } from 'react';
import './CommandeForm.css';

const CommandeForm = ({ selectedCommande, onSuccess }) => {
  const [formData, setFormData] = useState({
    idCOM: '',
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  useEffect(() => {
    if (selectedCommande) {
      setFormData(selectedCommande);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      idCOM: '',
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const method = selectedCommande ? 'PUT' : 'POST';
    const url = selectedCommande
      ? `http://localhost:3001/api/commandes/${selectedCommande.idCOM}`
      : 'http://localhost:3001/api/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  const handleDelete = async () => {
    if (!selectedCommande) return;

    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(
        `http://localhost:3001/api/commandes/${selectedCommande.idCOM}`,
        {
          method: 'DELETE'
        }
      );

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="commande-form">
      <input
        name="codeCli"
        placeholder="Numéro client"
        value={formData.codeCli}
        onChange={handleChange}
        required
      />
      <input
        name="codeArt"
        placeholder="Numéro article"
        value={formData.codeArt}
        onChange={handleChange}
        required
      />
      <input
        name="dateCom"
        type="date"
        placeholder="Date"
        value={formData.dateCom}
        onChange={handleChange}
        required
      />
      <input
        name="QteCom"
        placeholder="Quantité"
        value={formData.QteCom}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedCommande ? 'Modifier' : 'Ajouter'}
      </button>
      {selectedCommande && (
        <button type="button" onClick={handleDelete}>
          Supprimer
        </button>
      )}
    </form>
  );
};

export default CommandeForm;
